import React, { useEffect, useState } from "react";
import API from "../../api/api";
import FreelancerLayout from "../../components/FreelancerLayout";

const FreelancerDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user"));

  const [stats, setStats] = useState({
    totalProjects: 0,
    totalProposals: 0,
    acceptedProposals: 0,
    pendingProposals: 0,
  });

  const [projects, setProjects] = useState([]);

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    try {
      const projectsRes = await API.get("/projects");
      const proposalsRes = await API.get(
        "/proposals/freelancer/my-proposals"
      );

      const proposals = proposalsRes.data;
      const allProjects = projectsRes.data;

      const activeProjects = allProjects.filter(
        (p) => p.status === "active"
      );

      setStats({
        totalProjects: activeProjects.length,
        totalProposals: proposals.length,
        acceptedProposals: proposals.filter(
          (p) => p.status === "accepted"
        ).length,
        pendingProposals: proposals.filter(
          (p) => p.status === "pending"
        ).length,
      });

      setProjects(activeProjects);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <FreelancerLayout>
      <div className="max-w-7xl mx-auto">

        {/* Welcome Section */}
        <div className="mb-10">
          <h1 className="text-3xl font-bold text-gray-800">
            Welcome back, {user?.name} 👋
          </h1>
          <p className="text-gray-500 mt-2">
            Here's your freelancing overview
          </p>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <StatCard title="Active Projects" value={stats.totalProjects} />
          <StatCard title="Total Earnings" value="$52K" />
          <StatCard title="Avg Rating" value="4.9" />
          <StatCard title="Pending Proposals" value={stats.pendingProposals} />
        </div>

        {/* Main Section */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* Active Projects */}
          <div className="lg:col-span-2">
            <h2 className="text-xl font-semibold text-gray-800 mb-6">
              Active Projects
            </h2>

            {projects.length === 0 && (
              <div className="bg-white p-6 rounded-2xl shadow-sm border">
                No active projects available
              </div>
            )}

            {projects.map((project) => (
              <div
                key={project.id}
                className="bg-white p-6 rounded-2xl shadow-sm border mb-6 hover:shadow-md transition"
              >
                <h3 className="text-lg font-semibold mb-2">
                  {project.title}
                </h3>

                <p className="text-gray-500 mb-4">
                  {project.description}
                </p>

                <div className="flex justify-between text-sm text-gray-500">
                  <span>₹ {project.budget}</span>
                  <span>{project.status}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Profile Completion */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border">
            <h2 className="text-lg font-semibold mb-6">
              Profile Completion
            </h2>

            <Progress label="Basic Info" value={100} />
            <Progress label="Portfolio" value={75} />
            <Progress label="Skills" value={90} />
            <Progress label="Certifications" value={40} />
          </div>

        </div>

      </div>
    </FreelancerLayout>
  );
};

/* ============================= */
/* STAT CARD COMPONENT */
/* ============================= */

const StatCard = ({ title, value }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border hover:shadow-md transition">
    <p className="text-gray-500 text-sm">{title}</p>
    <h2 className="text-3xl font-bold mt-3 text-gray-800">
      {value}
    </h2>
  </div>
);

/* ============================= */
/* PROGRESS BAR COMPONENT */
/* ============================= */

const Progress = ({ label, value }) => (
  <div className="mb-5">
    <div className="flex justify-between text-sm mb-2">
      <span className="text-gray-600">{label}</span>
      <span className="text-gray-600">{value}%</span>
    </div>

    <div className="w-full bg-gray-200 h-2 rounded-full">
      <div
        className="bg-green-500 h-2 rounded-full transition-all duration-500"
        style={{ width: `${value}%` }}
      ></div>
    </div>
  </div>
);

export default FreelancerDashboard;
